import asyncio
import websockets
import json
import uuid
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.players = {}  # {websocket: player_data}
        self.player_id_to_websocket = {} # {player_id: websocket}
        self.items = {}  # {item_id: {'name': str, 'owner_id': str}}
        self.item_id_counter = 0
        self.pending_trades = {} # {trade_id: {'player1_id': str, 'player2_id': str, 'item_id': str, 'status': 'pending'|'accepted'}}
        self.trade_id_counter = 0
        self.lock = asyncio.Lock() # Global lock for critical sections (e.g., item transfers)

        # Initial items for testing
        self._add_test_items()

    def _generate_item_id(self):
        self.item_id_counter += 1
        return f"item_{self.item_id_counter}"

    def _generate_trade_id(self):
        self.trade_id_counter += 1
        return f"trade_{self.trade_id_counter}"

    def _add_test_items(self):
        # Create some initial items owned by 'server' or unowned
        self.items = {
            self._generate_item_id(): {'name': 'Sword of Destiny', 'owner_id': None},
            self._generate_item_id(): {'name': 'Shield of Ancients', 'owner_id': None},
            self._generate_item_id(): {'name': 'Health Potion', 'owner_id': None},
            self._generate_item_id(): {'name': 'Mana Potion', 'owner_id': None},
            self._generate_item_id(): {'name': 'Iron Dagger', 'owner_id': None},
        }

    async def register_player(self, websocket):
        player_id = str(uuid.uuid4()) # Unique ID for the player
        self.players[websocket] = {'id': player_id, 'inventory': []}
        self.player_id_to_websocket[player_id] = websocket
        print(f"Player {player_id} connected.")

        # Assign some items to the new player for testing
        player_inventory = []
        for item_id, item_data in list(self.items.items()):
            if item_data['owner_id'] is None:
                item_data['owner_id'] = player_id
                player_inventory.append(item_id)
                if len(player_inventory) >= 2: # Give each new player 2 unowned items
                    break
        self.players[websocket]['inventory'] = player_inventory

        await self.send_message(websocket, 'connected', {'player_id': player_id, 'inventory': self.get_player_inventory_details(player_id)})
        await self.broadcast_player_list()

    async def unregister_player(self, websocket):
        player_id = self.players[websocket]['id']
        del self.player_id_to_websocket[player_id]

        # Return items to 'unowned' status if player disconnects
        for item_id in self.players[websocket]['inventory']:
            if item_id in self.items:
                self.items[item_id]['owner_id'] = None # Item becomes unowned

        del self.players[websocket]
        print(f"Player {player_id} disconnected.")
        await self.broadcast_player_list()

    def get_player_inventory_details(self, player_id):
        # Helper to get full item details for a player's inventory
        websocket = self.player_id_to_websocket.get(player_id)
        if not websocket:
            return []
        
        inventory_ids = self.players[websocket]['inventory']
        return [{
            'item_id': item_id,
            'name': self.items[item_id]['name']
        } for item_id in inventory_ids if item_id in self.items and self.items[item_id]['owner_id'] == player_id]

    async def send_message(self, websocket, msg_type, payload):
        await websocket.send(json.dumps({'type': msg_type, 'payload': payload}))

    async def broadcast_player_list(self):
        player_list = [{'id': data['id']} for data in self.players.values()]
        for websocket in self.players:
            await self.send_message(websocket, 'player_list', {'players': player_list})

    async def handle_request_trade(self, websocket, player_id, item_id, target_player_id):
        async with self.lock:
            if player_id not in self.player_id_to_websocket:
                await self.send_message(websocket, 'trade_error', {'message': 'Your player ID not found.'})
                return
            if target_player_id not in self.player_id_to_websocket:
                await self.send_message(websocket, 'trade_error', {'message': 'Target player not found.'})
                return
            if item_id not in self.items or self.items[item_id]['owner_id'] != player_id:
                await self.send_message(websocket, 'trade_error', {'message': f"Item {item_id} not found or not owned by you."})
                return

            trade_id = self._generate_trade_id()
            self.pending_trades[trade_id] = {
                'player1_id': player_id, # Initiator
                'player2_id': target_player_id, # Target
                'item_id': item_id,
                'status': 'pending'
            }

            # Notify initiator
            await self.send_message(websocket, 'trade_request_sent', {'trade_id': trade_id, 'item_id': item_id, 'target_player_id': target_player_id})

            # Notify target player
            target_websocket = self.player_id_to_websocket[target_player_id]
            await self.send_message(target_websocket, 'trade_request_received', {
                'trade_id': trade_id,
                'initiator_id': player_id,
                'item_name': self.items[item_id]['name'],
                'item_id': item_id
            })
            print(f"Trade request {trade_id}: {player_id} wants to give {item_id} to {target_player_id}")


    async def handle_accept_trade(self, websocket, player_id, trade_id):
        async with self.lock:
            trade = self.pending_trades.get(trade_id)
            if not trade:
                await self.send_message(websocket, 'trade_error', {'message': f"Trade {trade_id} not found or expired."})
                return
            if trade['player2_id'] != player_id: # Only the target can accept
                await self.send_message(websocket, 'trade_error', {'message': "You are not authorized to accept this trade."})
                return
            if trade['status'] != 'pending':
                await self.send_message(websocket, 'trade_error', {'message': f"Trade {trade_id} is no longer pending."})
                return

            initiator_id = trade['player1_id']
            item_id = trade['item_id']

            # Double check item ownership before transfer
            if self.items[item_id]['owner_id'] != initiator_id:
                await self.send_message(websocket, 'trade_error', {'message': f"Item {item_id} is no longer owned by {initiator_id}. Trade aborted."})
                # Notify initiator as well
                initiator_websocket = self.player_id_to_websocket.get(initiator_id)
                if initiator_websocket:
                    await self.send_message(initiator_websocket, 'trade_failed', {'trade_id': trade_id, 'message': f"Item {item_id} was lost by owner before trade."})
                del self.pending_trades[trade_id]
                return

            # Perform the transfer
            self.items[item_id]['owner_id'] = player_id # Update item ownership

            # Update inventories
            initiator_websocket = self.player_id_to_websocket[initiator_id]
            self.players[initiator_websocket]['inventory'].remove(item_id)
            self.players[websocket]['inventory'].append(item_id)

            trade['status'] = 'accepted' # Mark trade as complete
            del self.pending_trades[trade_id] # Remove completed trade

            # Notify both players
            await self.send_message(websocket, 'trade_completed', {
                'trade_id': trade_id,
                'item_id': item_id,
                'new_owner_id': player_id,
                'old_owner_id': initiator_id,
                'inventory': self.get_player_inventory_details(player_id)
            })
            await self.send_message(initiator_websocket, 'trade_completed', {
                'trade_id': trade_id,
                'item_id': item_id,
                'new_owner_id': player_id,
                'old_owner_id': initiator_id,
                'inventory': self.get_player_inventory_details(initiator_id)
            })
            print(f"Trade {trade_id} completed: {initiator_id} gave {item_id} to {player_id}")

    async def handle_reject_trade(self, websocket, player_id, trade_id):
        async with self.lock:
            trade = self.pending_trades.get(trade_id)
            if not trade:
                await self.send_message(websocket, 'trade_error', {'message': f"Trade {trade_id} not found or expired."})
                return
            if trade['player2_id'] != player_id: # Only the target can reject
                await self.send_message(websocket, 'trade_error', {'message': "You are not authorized to reject this trade."})
                return
            if trade['status'] != 'pending':
                await self.send_message(websocket, 'trade_error', {'message': f"Trade {trade_id} is no longer pending."})
                return

            initiator_id = trade['player1_id']
            del self.pending_trades[trade_id] # Remove pending trade

            # Notify both players
            await self.send_message(websocket, 'trade_rejected', {'trade_id': trade_id, 'message': 'You rejected the trade.'})
            initiator_websocket = self.player_id_to_websocket.get(initiator_id)
            if initiator_websocket:
                await self.send_message(initiator_websocket, 'trade_rejected', {'trade_id': trade_id, 'message': f"{player_id} rejected your trade offer for {self.items[trade['item_id']]['name']}."})
            print(f"Trade {trade_id} rejected by {player_id}")

    async def handle_drop_item(self, websocket, player_id, item_id):
        async with self.lock:
            if item_id not in self.items or self.items[item_id]['owner_id'] != player_id:
                await self.send_message(websocket, 'inventory_error', {'message': f"Item {item_id} not found or not owned by you."})
                return

            self.items[item_id]['owner_id'] = None # Item becomes unowned
            self.players[websocket]['inventory'].remove(item_id)

            await self.send_message(websocket, 'item_dropped', {'item_id': item_id, 'inventory': self.get_player_inventory_details(player_id)})
            print(f"Player {player_id} dropped item {item_id}")

    async def handle_message(self, websocket, message):
        try:
            data = json.loads(message)
            msg_type = data.get('type')
            payload = data.get('payload', {})
            player_id = self.players[websocket]['id']

            print(f"Received message from {player_id}: {msg_type} with payload {payload}")

            if msg_type == 'request_trade':
                await self.handle_request_trade(websocket, player_id, payload.get('item_id'), payload.get('target_player_id'))
            elif msg_type == 'accept_trade':
                await self.handle_accept_trade(websocket, player_id, payload.get('trade_id'))
            elif msg_type == 'reject_trade':
                await self.handle_reject_trade(websocket, player_id, payload.get('trade_id'))
            elif msg_type == 'drop_item':
                await self.handle_drop_item(websocket, player_id, payload.get('item_id'))
            elif msg_type == 'request_inventory':
                await self.send_message(websocket, 'inventory_update', {'inventory': self.get_player_inventory_details(player_id)})
            elif msg_type == 'request_all_items': # For admin/debugging
                all_item_details = [
                    {'item_id': item_id, 'name': data['name'], 'owner_id': data['owner_id']}
                    for item_id, data in self.items.items()
                ]
                await self.send_message(websocket, 'all_items_data', {'items': all_item_details})
            else:
                print(f"Unknown message type: {msg_type}")

        except json.JSONDecodeError:
            print(f"Received invalid JSON: {message}")
        except Exception as e:
            print(f"Error handling message: {e}")

    async def handler(self, websocket, path):
        await self.register_player(websocket)
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosedOK:
            pass
        except Exception as e:
            print(f"Handler error: {e}")
        finally:
            await self.unregister_player(websocket)

async def main():
    game_server = GameServer()
    # Using '0.0.0.0' to listen on all available network interfaces
    async with websockets.serve(game_server.handler, "0.0.0.0", 8765):
        print("Game server started on ws://0.0.0.0:8765")
        await asyncio.Future() # Run forever

if __name__ == "__main__":
    asyncio.run(main())